// 전달 임계 조건 확인 [IF]
// relay_conditions 비어 있으면 모두 전달 (초기 운영). 운영 팀이 규칙 주입 시 동작.
// webhook typeVersion 2: body in $json.body
const raw = $json;
const input = raw.body || raw;
const env = (typeof process !== 'undefined' && process.env) ? process.env : {};

let config = {};
let configStatus = 'empty';
const configRaw = env.BRIDGE_RELAY_CONFIG_JSON || input.bridge_config_json || null;
if (configRaw) {
  try {
    config = typeof configRaw === 'string' ? JSON.parse(configRaw) : configRaw;
    configStatus = 'loaded';
  } catch (e) {
    config = {};
    configStatus = 'parse_error:' + e.message;
  }
}

const relayConditions = Array.isArray(config.relay_conditions) ? config.relay_conditions : [];
const relayThreshold = Number.isFinite(Number(config.relay_threshold)) ? Number(config.relay_threshold) : null;

let shouldRelay = true;
let rejectReason = null;

if (relayThreshold !== null && Number(input.approve_ratio || 0) < relayThreshold) {
  shouldRelay = false;
  rejectReason = 'relay_threshold_not_met';
}

if (shouldRelay && relayConditions.length > 0) {
  const matchesSomeCondition = relayConditions.some(cond => {
    if (cond.result && input.result !== cond.result) return false;
    if (cond.min_approve_ratio && (input.approve_ratio || 0) < cond.min_approve_ratio) return false;
    return true;
  });
  if (!matchesSomeCondition) {
    shouldRelay = false;
    rejectReason = 'relay_condition_not_met';
  }
}

return [{
  json: {
    ...input,
    _bridge_decision: shouldRelay ? 'relay' : 'drop',
    _bridge_reject_reason: rejectReason,
    _bridge_config: {
      source: configRaw ? 'env_or_payload' : 'empty_default',
      status: configStatus,
      relay_threshold: relayThreshold,
      relay_conditions_count: relayConditions.length
    },
    _bridge_ts: new Date().toISOString()
  }
}];

// Honcho DOWN fallback — log to console (email alert requires SMTP credentials)
const decision = $('전달 조건 필터 [IF]').first().json;
console.error('[HONCHO DOWN] 인프라 결정 전달 불가:', JSON.stringify(decision));
return [{ json: { _honcho_down: true, ts: new Date().toISOString(), decision } }];

// 업무 workspace에 인프라 결정 기록
// 활동 기록 계약 형식 (고정)
// n8n v1: $('nodeName').first().json 으로 이전 노드 데이터 접근
const decision = $('전달 조건 필터 [IF]').first().json;

const activityRecord = {
  ts: new Date().toISOString(),
  type: 'infra_decision_relayed',
  actor: decision.actor || 'system',
  payload: {
    topic: decision.topic,
    result: decision.result,
    method: decision.method,
    tally: decision.tally,
    approve_ratio: decision.approve_ratio,
    bridge_ts: decision._bridge_ts
  }
};

return [{ json: { activity_record: activityRecord } }];

// 드롭된 결정 기록 (감사 로그용)
const input = $input.item.json;
return [{
  json: {
    _dropped: true,
    reason: input._bridge_reject_reason,
    original: input,
    ts: new Date().toISOString()
  }
}];
